 1	import React, { ChangeEvent, Dispatch, FC, SetStateAction, useCallback } from 'react';
 2	
 3	import FormPFSelect from '@kubevirt-utils/components/FormPFSelect/FormPFSelect';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { BinaryUnit, toIECUnit } from '@kubevirt-utils/utils/units';
 6	import { NumberInput, SelectOption, Split, SplitItem } from '@patternfly/react-core';
 7	
 8	import { fromIECUnit } from '../../../MigrationPolicyEditModal/utils/utils';
 9	
10	type BandwidthInputProps = {
11	  setState: Dispatch<
12	    SetStateAction<{
13	      unit: BinaryUnit;
14	      value: number;
15	    }>
16	  >;
17	  state: {
18	    unit: BinaryUnit;
19	    value: number;
20	  };
21	};
22	
23	const unitOptions = [BinaryUnit.Ki, BinaryUnit.Mi, BinaryUnit.Gi];
24	
25	const BandwidthInput: FC<BandwidthInputProps> = ({ setState, state }) => {
26	  const { t } = useKubevirtTranslation();
27	
28	  const onSelectUnit = useCallback(
29	    (_, newUnit: BinaryUnit) => {
30	      setState((prev) => ({ ...prev, unit: fromIECUnit(newUnit) }));
31	    },
32	    [setState],
33	  );
34	
35	  return (
36	    <Split hasGutter>
37	      <SplitItem>
38	        <NumberInput
39	          onChange={(event: ChangeEvent<HTMLInputElement>) =>
40	            +event.target.value >= 0 &&
41	            setState((prev) => ({ ...prev, value: +event.target.value }))
42	          }
43	          min={0}
44	          minusBtnAriaLabel={t('Decrement')}
45	          onMinus={() => setState((prev) => ({ ...prev, value: --prev.value }))}
46	          onPlus={() => setState((prev) => ({ ...prev, value: prev?.value + 1 || 1 }))}
47	          plusBtnAriaLabel={t('Increment')}
48	          value={state?.value}
49	        />
50	      </SplitItem>
51	      <SplitItem>
52	        <FormPFSelect
53	          onSelect={onSelectUnit}
54	          selected={state?.unit}
55	          selectedLabel={toIECUnit(state?.unit)}
56	        >
57	          {unitOptions.map((unitOption) => (
58	            <SelectOption key={unitOption} value={unitOption}>
59	              {toIECUnit(unitOption)}
60	            </SelectOption>
61	          ))}
62	        </FormPFSelect>
63	      </SplitItem>
64	    </Split>
65	  );
66	};
67	
68	export default BandwidthInput;

